// src/components/Sidebar.jsx
import React from "react";
import { NavLink, useNavigate } from "react-router-dom";
import {
    Home, Compass, MessageSquare, Users, User,
    LogOut, Zap, Sun, Moon,
} from "lucide-react";
import { useAuth } from "../context/AuthContext";

const NAV_ITEMS = [
    { to: "/dashboard", icon: Home, label: "Home" },
    { to: "/dashboard/discover", icon: Compass, label: "Discover" },
    { to: "/dashboard/messages", icon: MessageSquare, label: "Messenger" },
    { to: "/dashboard/network", icon: Users, label: "My Network" },
    { to: "/dashboard/profile", icon: User, label: "Profile" },
];

export default function Sidebar() {
    const { user, logout, theme, toggleTheme } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate("/");
    };

    return (
        <aside style={sidebarStyle(theme)}>
            {/* Brand */}
            <div style={styles.brand}>
                <div style={styles.brandIcon}>
                    <Zap size={20} color="#fff" fill="#fff" />
                </div>
                <span style={styles.brandText}>SkillSync</span>
            </div>

            {/* Nav */}
            <nav style={styles.nav}>
                {NAV_ITEMS.map(({ to, icon: Icon, label }) => (
                    <NavLink
                        key={to}
                        to={to}
                        end={to === "/dashboard"}
                        style={({ isActive }) => navItemStyle(isActive, theme)}
                    >
                        {({ isActive }) => (
                            <>
                                <div style={indicatorStyle(isActive)} />
                                <div style={iconWrapStyle(isActive)}>
                                    <Icon size={18} />
                                </div>
                                <span style={{ fontWeight: isActive ? 600 : 400 }}>{label}</span>
                            </>
                        )}
                    </NavLink>
                ))}
            </nav>

            {/* Bottom section */}
            <div style={styles.bottomSection}>
                {/* Theme Toggle */}
                <button
                    style={themeToggleStyle(theme)}
                    onClick={toggleTheme}
                    title={`Switch to ${theme === "dark" ? "light" : "dark"} mode`}
                >
                    {theme === "dark" ? (
                        <>
                            <Sun size={16} color="#f5c518" />
                            <span style={{ fontSize: "0.82rem", fontWeight: 500 }}>Light Mode</span>
                        </>
                    ) : (
                        <>
                            <Moon size={16} color="#6C63FF" />
                            <span style={{ fontSize: "0.82rem", fontWeight: 500 }}>Dark Mode</span>
                        </>
                    )}
                </button>

                {/* User chip */}
                {user && (
                    <div style={userChipStyle(theme)}>
                        <div style={styles.userAvatar}>
                            {(user.avatar || user.name?.[0] || "U").toString()[0]}
                        </div>
                        <div style={styles.userText}>
                            <p style={styles.userName}>{user.name || "User"}</p>
                            <p style={styles.userRole}>{user.email || ""}</p>
                        </div>
                    </div>
                )}

                {/* Logout */}
                <button style={logoutStyle(theme)} onClick={handleLogout}>
                    <LogOut size={16} />
                    <span>Logout</span>
                </button>
            </div>
        </aside>
    );
}

/* ---- Dynamic style helpers ---- */
const sidebarStyle = (theme) => ({
    width: "240px",
    minWidth: "240px",
    height: "100vh",
    position: "sticky",
    top: 0,
    display: "flex",
    flexDirection: "column",
    background: theme === "dark"
        ? "rgba(12, 12, 20, 0.92)"
        : "rgba(240, 242, 255, 0.96)",
    backdropFilter: "blur(16px)",
    WebkitBackdropFilter: "blur(16px)",
    borderRight: theme === "dark"
        ? "1px solid rgba(255,255,255,0.07)"
        : "1px solid rgba(108, 99, 255, 0.15)",
    padding: "28px 0 20px",
    zIndex: 100,
    transition: "background 0.25s, border-color 0.25s",
    overflowY: "auto",
});

const navItemStyle = (isActive, theme) => ({
    display: "flex",
    alignItems: "center",
    gap: "12px",
    padding: "11px 20px 11px 24px",
    position: "relative",
    cursor: "pointer",
    textDecoration: "none",
    color: isActive
        ? (theme === "dark" ? "#fff" : "#1A1A30")
        : (theme === "dark" ? "rgba(255,255,255,0.5)" : "rgba(26,26,48,0.55)"),
    fontSize: "0.92rem",
    background: isActive
        ? (theme === "dark" ? "rgba(108,99,255,0.15)" : "rgba(108,99,255,0.10)")
        : "transparent",
    borderRadius: "0 12px 12px 0",
    marginRight: "12px",
    transition: "all 0.2s",
});

const indicatorStyle = (isActive) => ({
    position: "absolute",
    left: 0,
    top: "50%",
    transform: "translateY(-50%)",
    width: "3px",
    height: isActive ? "28px" : "0px",
    background: "linear-gradient(180deg, #6C63FF, #00c6ff)",
    borderRadius: "0 3px 3px 0",
    transition: "height 0.22s ease",
});

const iconWrapStyle = (isActive) => ({
    width: "34px",
    height: "34px",
    borderRadius: "10px",
    background: isActive
        ? "linear-gradient(135deg, #6C63FF, #00c6ff)"
        : "rgba(255,255,255,0.06)",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    boxShadow: isActive ? "0 4px 14px rgba(108,99,255,0.35)" : "none",
    transition: "all 0.22s",
    flexShrink: 0,
});

const themeToggleStyle = (theme) => ({
    display: "flex",
    alignItems: "center",
    gap: "10px",
    width: "calc(100% - 28px)",
    margin: "0 14px 12px",
    padding: "10px 14px",
    background: theme === "dark" ? "rgba(255,255,255,0.06)" : "rgba(108,99,255,0.08)",
    border: theme === "dark" ? "1px solid rgba(255,255,255,0.08)" : "1px solid rgba(108,99,255,0.2)",
    borderRadius: "10px",
    color: theme === "dark" ? "rgba(255,255,255,0.75)" : "#4A4A6A",
    cursor: "pointer",
    transition: "all 0.2s",
    fontSize: "0.82rem",
});

const userChipStyle = (theme) => ({
    display: "flex",
    alignItems: "center",
    gap: "10px",
    margin: "4px 14px 12px",
    padding: "10px 12px",
    background: theme === "dark" ? "rgba(255,255,255,0.04)" : "rgba(108,99,255,0.06)",
    borderRadius: "12px",
    border: theme === "dark" ? "1px solid rgba(255,255,255,0.06)" : "1px solid rgba(108,99,255,0.12)",
});

const logoutStyle = (theme) => ({
    display: "flex",
    alignItems: "center",
    gap: "10px",
    width: "calc(100% - 28px)",
    margin: "0 14px",
    padding: "10px 14px",
    background: "transparent",
    border: "1px solid rgba(231,76,60,0.25)",
    borderRadius: "10px",
    color: "#e74c3c",
    cursor: "pointer",
    fontSize: "0.88rem",
    fontWeight: 500,
    transition: "all 0.2s",
});

const styles = {
    brand: {
        display: "flex",
        alignItems: "center",
        gap: "12px",
        padding: "0 24px 28px",
        borderBottom: "1px solid rgba(255,255,255,0.06)",
        marginBottom: "12px",
    },
    brandIcon: {
        width: "36px",
        height: "36px",
        borderRadius: "10px",
        background: "linear-gradient(135deg, #6C63FF, #00c6ff)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        boxShadow: "0 4px 14px rgba(108,99,255,0.4)",
    },
    brandText: {
        fontFamily: "'Space Grotesk', sans-serif",
        fontWeight: 700,
        fontSize: "1.18rem",
        background: "linear-gradient(135deg, #6C63FF, #00c6ff)",
        WebkitBackgroundClip: "text",
        WebkitTextFillColor: "transparent",
        backgroundClip: "text",
    },
    nav: {
        display: "flex",
        flexDirection: "column",
        gap: "4px",
        flex: 1,
    },
    bottomSection: {
        marginTop: "auto",
        paddingTop: "16px",
        borderTop: "1px solid rgba(255,255,255,0.06)",
    },
    userAvatar: {
        width: "32px",
        height: "32px",
        borderRadius: "50%",
        background: "linear-gradient(135deg, #6C63FF, #00c6ff)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        fontSize: "0.9rem",
        fontWeight: 700,
        color: "#fff",
        flexShrink: 0,
    },
    userText: { overflow: "hidden" },
    userName: {
        fontSize: "0.85rem",
        fontWeight: 600,
        whiteSpace: "nowrap",
        overflow: "hidden",
        textOverflow: "ellipsis",
    },
    userRole: {
        fontSize: "0.72rem",
        opacity: 0.55,
        whiteSpace: "nowrap",
        overflow: "hidden",
        textOverflow: "ellipsis",
    },
};
